commits.content:
.enneagram-page {
  display: flex;
  min-height: 100vh;
  background-color: #f2f5f8;
  max-width: 1440px;
  margin: 0 auto;
  width: 100%;
}

.enneagram-main {
  flex: 1;
  padding: 4rem 3rem;
  margin-top: 30px;
}

.enneagram-content {
  max-width: 842px;
  margin: 0 auto;
}

/* Вводная секция */
.enneagram-intro-section {
  margin-bottom: 3rem;
  margin-top: 30px;
  margin-left: -70px;
  width: 100%;
}

.enneagram-title {
  font-family: 'Unbounded', sans-serif;
  font-size: 40px;
  font-weight: 400;
  color: #262626;
  margin: 0 0 1.5rem 0;
  line-height: 1.2;
}

.enneagram-description {
  margin: 0;
}

.enneagram-description p {
  font-family: 'Montserrat', sans-serif;
  font-size: 16px;
  font-weight: 500;
  line-height: 130%;
  color: #262626;
  margin: 0;
  text-align: justify;
  max-width: 752px;
}

.enneagram-description strong {
  font-weight: 700;
  color: #1a1a1a;
}

/* Секция с роботом и диаграммой */
.enneagram-robot-section {
  display: flex;
  align-items: flex-start;
  gap: 2rem;
  margin-bottom: 3rem;
  margin-left: -70px;
  margin-top: 30px;
  width: 100%;
  position: relative;
}

.enneagram-robot-bubble-container {
  flex: 1;
  position: relative;
}

.enneagram-bubble-wrapper {
  display: flex;
  align-items: flex-start;
  gap: 1rem;
  position: relative;
}

.enneagram-robot-image {
  flex-shrink: 0;
  align-self: flex-start;
  position: relative;
  z-index: 1;
  margin-left: -50px;
}

.enneagram-robot-image img {
  width: 300px;
  height: 300px;
  object-fit: contain;
}

.enneagram-speech-bubble {
  background-size: 100% 100%;
  background-repeat: no-repeat;
  background-position: center;
  border: none;
  position: absolute;
  right: -110px;
  top: -10px;
  width: 400px;
  height: 190px;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 10px;
  box-sizing: border-box;
  z-index: 2;
}

.enneagram-speech-bubble p {
  font-family: 'Montserrat', sans-serif;
  font-size: 16px;
  font-weight: 500;
  line-height: 130%;
  color: #262626;
  margin: 0;
  text-align: justify;
  width: 100%;
  z-index: 1;
  position: relative;
  white-space: normal;
  padding: 0;
  padding-left: 45px;
  box-sizing: border-box;
  overflow-wrap: break-word;
  word-wrap: break-word;
}

.enneagram-speech-bubble p strong {
  display: block;
  padding-top: 5px;
}

@media (max-width: 768px) {
  .enneagram-speech-bubble {
    display: none;
  }
}

.enneagram-diagram-container {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
  z-index: 1;
  margin-left: 100px;
}

.enneagram-diagram {
  width: 250px;
  height: 250px;
  object-fit: contain;
}

@media (max-width: 768px) {
  .enneagram-robot-section {
    flex-direction: column;
    margin-left: 0;
    gap: 1.5rem;
  }

  .enneagram-robot-image {
    align-self: center;
  }

  .enneagram-robot-image img {
    width: 200px;
    height: 200px;
  }

  .enneagram-speech-bubble {
    width: 100%;
    max-width: 400px;
    margin-left: 0;
    margin-top: 0;
    min-height: 164px;
    height: auto;
  }

  .enneagram-diagram {
    margin: 0 auto;
  }
}

/* Секция с вопросами */
.enneagram-question-section-wrapper {
  margin-top: calc(3rem + 50px);
  margin-left: -70px;
}

.enneagram-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
  gap: 10px;
}

.enneagram-back-button {
  background-color: #347aec;
  color: white;
  border: none;
  border-radius: 29px;
  padding: 6px 29px;
  font-family: 'Unbounded', sans-serif;
  font-size: 14px;
  font-weight: 400;
  cursor: pointer;
  transition: background-color 0.5s;
  height: 30px;
  white-space: nowrap;
}

.enneagram-back-button:hover {
  background-color: #6764e7;
}

.enneagram-counter {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: flex-start;
  border-radius: 29px;
  height: 30px;
  width: 100%;
  max-width: 726px;
  overflow: hidden;
  background-color: white;
  font-family: 'Montserrat', sans-serif;
  font-size: 16px;
  font-weight: 600;
}

.enneagram-counter span {
  position: relative;
  z-index: 2;
  color: #262626;
  padding: 0 15px;
  white-space: nowrap;
}

.enneagram-progress-bar {
  position: absolute;
  top: 0;
  left: 0;
  height: 100%;
  background-color: rgba(52, 122, 236, 0.4);
  transition: width 0.3s ease-in-out;
  z-index: 1;
}

.enneagram-question-section {
  width: 100%;
  background-color: white;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
  padding: 25px 40px;
  border-radius: 10px;
  margin-bottom: 20px;
  min-height: 100px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.enneagram-question-text {
  font-family: 'Unbounded', sans-serif;
  font-size: 16px;
  font-weight: 400;
  line-height: 130%;
  text-align: center;
  color: #262626;
  margin: 0;
}

@media (min-width: 768px) {
  .enneagram-question-text {
    font-size: 22px;
  }
}

.enneagram-get-result-button {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 5px;
  width: 100%;
  padding: 26px 0;
  background: none;
  border: none;
  cursor: pointer;
}

.enneagram-get-result-button span {
  color: #262626;
  text-align: center;
  font-family: 'Unbounded', sans-serif;
  font-size: 16px;
}

@media (min-width: 768px) {
  .enneagram-get-result-button span {
    font-size: 22px;
  }
}

.enneagram-arrow-icon {
  width: 18px;
  height: 10px;
}

@media (min-width: 768px) {
  .enneagram-arrow-icon {
    width: 22px;
    height: 11px;
  }
}

.enneagram-buttons {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  width: 100%;
  margin-bottom: 20px;
}

@media (min-width: 768px) {
  .enneagram-buttons {
    flex-direction: row;
    justify-content: center;
  }
}

.enneagram-answer-button-middle {
  order: 2;
}

@media (min-width: 768px) {
  .enneagram-answer-button-middle {
    order: 0;
  }
}

.enneagram-answer-button {
  background-color: #347aec;
  color: white;
  border: none;
  border-radius: 10px;
  padding: 6px 10px;
  font-family: 'Unbounded', sans-serif;
  font-size: 14px;
  font-weight: 400;
  cursor: pointer;
  transition: background-color 0.5s;
  width: 100%;
  height: 40px;
}

@media (min-width: 768px) {
  .enneagram-answer-button {
    width: 270px;
    height: 50px;
  }
}

.enneagram-answer-button:hover:not(:disabled) {
  background-color: #6764e7;
}

.enneagram-answer-button:disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.enneagram-navigation {
  display: flex;
  justify-content: center;
  margin-top: 20px;
  margin-bottom: 50px;
}

@media (min-width: 768px) {
  .enneagram-navigation {
    margin-bottom: 0;
  }
}

.enneagram-prev-button {
  background: transparent;
  border: none;
  color: #000;
  font-size: 12px;
  font-weight: 500;
  padding: 3px 6px;
  border-radius: 8px;
  width: 140px;
  height: 17px;
  cursor: pointer;
  transition: font-weight 0.3s;
}

.enneagram-prev-button:hover {
  font-weight: bold;
}

.enneagram-result {
  margin-top: 20px;
  margin-bottom: 50px;
  overflow: hidden;
  transition: max-height 0.3s ease-in-out;
  display: flex;
  flex-direction: column;
  align-items: center;
}

@media (min-width: 768px) {
  .enneagram-result {
    flex-direction: row;
    align-items: flex-start;
    justify-content: space-between;
  }
}

.enneagram-result-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 100%;
}

@media (min-width: 768px) {
  .enneagram-result-content {
    flex-direction: row;
    align-items: flex-start;
    justify-content: space-between;
  }
}

.enneagram-result-image {
  margin-bottom: 26px;
}

@media (min-width: 768px) {
  .enneagram-result-image {
    margin-bottom: 0;
  }
}

.enneagram-result-img {
  width: 300px;
  height: 300px;
  border-radius: 15px;
  object-fit: contain;
}

.enneagram-result-text {
  width: 100%;
  max-width: 520px;
}

@media (min-width: 768px) {
  .enneagram-result-text {
    margin-left: 0;
  }
}

.enneagram-result-title {
  text-align: center;
  font-family: 'Unbounded', sans-serif;
  font-size: 22px;
  margin-bottom: 10px;
  color: #262626;
}

@media (min-width: 768px) {
  .enneagram-result-title {
    text-align: left;
    font-size: 30px;
  }
}

.enneagram-result-type {
  width: 60px;
  background-color: #347aec;
  color: white;
  border-radius: 5px;
  padding: 3px;
  text-align: center;
  margin: 0 auto 20px;
  font-size: 14px;
}

@media (min-width: 768px) {
  .enneagram-result-type {
    margin: 0 0 20px;
  }
}

.enneagram-result-description,
.enneagram-result-field {
  font-size: 16px;
  font-weight: 500;
  text-align: justify;
  margin-bottom: 20px;
  line-height: 1.6;
  color: #262626;
}

.enneagram-result-label {
  color: #347aec;
  font-weight: 600;
}

@media (max-width: 768px) {
  .enneagram-main {
    padding: 2.5rem 1.5rem;
  }

  .enneagram-intro-section {
    margin-left: 0;
    margin-top: 0;
  }

  .enneagram-title {
    font-size: 28px;
  }

  .enneagram-robot-section {
    flex-direction: column;
    margin-left: 0;
    gap: 1.5rem;
  }

  .enneagram-bubble-wrapper {
    flex-direction: column;
    align-items: stretch;
    gap: 0.75rem;
  }

  .enneagram-robot-image {
    align-self: center;
  }

  .enneagram-robot-image img {
    width: 250px;
    height: auto;
  }

  .enneagram-speech-bubble {
    width: 100%;
    height: auto;
    min-height: 90px;
    padding: 0.9rem 1rem;
    background-size: 100% 100%;
    background-position: center;
    margin-left: 0;
    margin-top: 0;
  }

  .enneagram-speech-bubble p {
    font-size: 16px;
    line-height: 1.4;
  }

  .enneagram-diagram {
    width: 100%;
    max-width: 300px;
  }

  .enneagram-question-section-wrapper {
    margin-left: 0;
    margin-top: 2rem;
  }

  .enneagram-header {
    flex-direction: column;
    align-items: stretch;
  }

  .enneagram-back-button {
    width: 100%;
    margin-bottom: 10px;
  }

  .enneagram-counter {
    width: 100%;
  }

  .enneagram-question-section {
    padding: 19px 25px;
  }

  .enneagram-buttons {
    flex-direction: column;
  }

  .enneagram-answer-button {
    width: 100%;
  }
}
